if (envVars.NODE_ENV !== "test") {
  getTransporter().then((transporter) => transporter.verify((error) => {
    if (error) {
      console.error("[EmailSender] SMTP connection FAILED:", error.message);
    } else {
      console.log("[EmailSender] SMTP server is ready");
    }
  })).catch((error) => {
    console.error("[EmailSender] SMTP connection FAILED:", error.message);
  });
}
