// src/modules/studySession/studySession.validation.ts
import { z as z4 } from "zod";
var createSessionSchema = z4.object({
  clusterId: z4.string().min(1, "clusterId must not be empty"),
  title: z4.string().min(3, "Title must be at least 3 characters").max(200),
  description: z4.string().max(2e3).optional(),
  scheduledAt: z4.string().min(1, "date (scheduledAt) is required").datetime({ message: "date must be a valid ISO 8601 datetime string" }),
  location: z4.string().max(200).optional(),
  taskDeadline: z4.string().datetime({ message: "deadline must be a valid ISO 8601 datetime string" }).optional(),
  templateId: z4.string().optional(),
  taskMode: z4.enum(["template", "individual", "none"]).optional(),
  individualTasks: z4.array(
    z4.object({
      studentProfileId: z4.string().min(1),
      title: z4.string().min(1).max(300),
      description: z4.string().max(2e3).optional()
    })
  ).optional()
});
var updateSessionSchema = z4.object({
  title: z4.string().min(3).max(200).optional(),
  description: z4.string().max(2e3).optional(),
  status: z4.enum(["upcoming", "ongoing", "completed", "cancelled"]).optional(),
  date: z4.string().datetime({ message: "date must be a valid ISO 8601 datetime string" }).optional(),
  durationMins: z4.number().optional(),
  location: z4.string().max(200).optional(),
  taskDeadline: z4.string().datetime({ message: "deadline must be a valid ISO 8601 datetime string" }).optional(),
  recordingUrl: z4.string().optional(),
  recordingNotes: z4.string().optional(),
  templateId: z4.string().optional()
}).refine((d) => Object.keys(d).length > 0, {
  message: "At least one field must be provided to update"
});
var attendanceRecordSchema = z4.object({
  studentId: z4.string().min(1, "studentId must not be empty"),
  status: z4.enum(["PRESENT", "ABSENT", "EXCUSED"], {
    message: 'status must be one of: "PRESENT", "ABSENT", or "EXCUSED"'
  }),
  note: z4.string().max(500).optional()
});
var submitAttendanceSchema = z4.object({
  attendance: z4.array(attendanceRecordSchema).min(1, "attendance array must have at least one record")
});
var agendaBlockSchema = z4.object({
  startTime: z4.string().min(1, "startTime is required").regex(/^\d{2}:\d{2}$/, 'startTime must be in HH:MM format (e.g. "14:00")'),
  durationMins: z4.number({ message: "durationMins must be a number" }).int().min(1, "durationMins must be at least 1"),
  topic: z4.string().min(1, "topic must not be empty").max(300),
  presenter: z4.string().max(150).optional()
});
var saveAgendaSchema = z4.object({
  blocks: z4.array(agendaBlockSchema).max(100)
});
var attendanceWarningConfigSchema = z4.object({
  threshold: z4.number().int().min(1).max(100).optional(),
  message: z4.string().trim().min(1).max(1e3).optional()
}).refine((value) => Object.keys(value).length > 0, {
  message: "At least one field must be provided"
});
var submitFeedbackSchema = z4.object({
  rating: z4.number({ message: "rating must be a number" }).int().min(1, "rating must be between 1 and 5").max(5, "rating must be between 1 and 5"),
  comment: z4.string().max(2e3).optional()
});
var replayNoteSchema = z4.object({
  timestamp: z4.string().min(1, "timestamp is required").regex(/^\d{2}:\d{2}$/, 'timestamp must be in HH:MM format (e.g. "14:35")'),
  note: z4.string().min(1, "note must not be empty").max(500)
});
var attachReplaySchema = z4.object({
  recordingUrl: z4.string().min(1, "recordingUrl is required").url("recordingUrl must be a valid URL"),
  notes: z4.array(replayNoteSchema).optional()
});

