// src/middleware/globalErrorHandler.ts
import status20 from "http-status";
import z8 from "zod";

// src/errorHelpers/handleZodError.ts
import status19 from "http-status";
var handleZodError = (err) => {
  const statusCode = status19.BAD_REQUEST;
  const message = "Zod Validation Error";
  const errorSources = [];
  err.issues.forEach((issue) => {
    errorSources.push({
      path: issue.path.join(" => "),
      message: issue.message
    });
  });
  return {
    success: false,
    message,
    errorSources,
    statusCode
  };
};

// src/middleware/globalErrorHandler.ts
var globalErrorHandler = async (err, req, res, next) => {
  if (envVars.NODE_ENV === "development") {
    console.log("Error from Global Error Handler", err);
  }
  if (req.file?.path) {
    await deleteFileFromCloudinary(req.file.path);
  }
  let errorSources = [];
  let statusCode = status20.INTERNAL_SERVER_ERROR;
  let message = "Internal Server Error";
  let stack = void 0;
  if (err instanceof z8.ZodError) {
    const simplifiedError = handleZodError(err);
    statusCode = simplifiedError.statusCode;
    message = simplifiedError.message;
    errorSources = [...simplifiedError.errorSources];
    stack = err.stack;
  } else if (err instanceof AppError_default) {
    statusCode = err.statusCode;
    message = err.message;
    stack = err.stack;
    errorSources = [
      {
        path: "",
        message: err.message
      }
    ];
  } else if (err instanceof Error) {
    statusCode = status20.INTERNAL_SERVER_ERROR;
    message = err.message;
    stack = err.stack;
    errorSources = [
      {
        path: "",
        message: err.message
      }
    ];
  }
  const isDev = envVars.NODE_ENV === "development";
  const errorResponse = { success: false, message, errorSources };
  if (isDev) {
    errorResponse.error = err;
    if (stack) errorResponse.stack = stack;
  }
  res.status(statusCode).json(errorResponse);
};

