import { Router as Router34 } from "express";

// src/modules/notification/notification.controller.ts
import status71 from "http-status";

// src/modules/notification/notification.service.ts
import status70 from "http-status";

// src/modules/notification/notification.utils.ts
var currentUserNotificationWhere = (userId, notificationId) => ({
  id: notificationId,
  userId
});

// src/modules/notification/notification.service.ts
var listForCurrentUser = async (userId, query) => {
  const typeFilter = query.type ? { type: query.type } : {};
  const [notifications, unreadCount] = await Promise.all([
    prisma.notification.findMany({
      where: {
        userId,
        ...typeFilter,
        ...query.unread === void 0 ? {} : { isRead: !query.unread ? true : false }
      },
      orderBy: [{ createdAt: "desc" }, { id: "desc" }],
      take: query.limit
    }),
    prisma.notification.count({
      where: { userId, ...typeFilter, isRead: false }
    })
  ]);
  return { notifications, unreadCount };
};
var markReadForCurrentUser = async (userId, notificationId) => {
  const result = await prisma.notification.updateMany({
    where: currentUserNotificationWhere(userId, notificationId),
    data: { isRead: true }
  });
  if (result.count === 0) throw new AppError_default(status70.NOT_FOUND, "Notification not found");
  return prisma.notification.findFirst({
    where: currentUserNotificationWhere(userId, notificationId)
  });
};
var notificationService = { listForCurrentUser, markReadForCurrentUser };

// src/modules/notification/notification.controller.ts
var list = catchAsync(async (req, res) => {
  const query = req.validatedQuery;
  const data = await notificationService.listForCurrentUser(req.user.userId, query);
  sendResponse(res, { status: status71.OK, success: true, message: "Notifications", data });
});
var markRead = catchAsync(async (req, res) => {
  const data = await notificationService.markReadForCurrentUser(req.user.userId, req.params.id);
  sendResponse(res, { status: status71.OK, success: true, message: "Notification marked as read", data });
});
var notificationController = { list, markRead };

// src/modules/notification/notification.validation.ts
import { z as z13 } from "zod";
var notificationListQuerySchema = z13.object({
  type: z13.string().trim().min(1).max(80).optional(),
  unread: z13.enum(["true", "false"]).transform((value) => value === "true").optional(),
  limit: z13.coerce.number().int().min(1).max(100).default(20)
}).strict();
var notificationIdParamsSchema = z13.object({
  id: z13.string().uuid()
}).strict();

// src/modules/notification/notification.route.ts
var router34 = Router34();
router34.get("/", checkAuth(), validateRequest(notificationListQuerySchema, "query"), notificationController.list);
router34.patch("/:id/read", checkAuth(), validateRequest(notificationIdParamsSchema, "params"), notificationController.markRead);
var notificationRouter = router34;

